                    voted_at TIMESTAMP,
                    executed_at TIMESTAMP,
                    
                    FOREIGN KEY (session_id) REFERENCES collective_reasoning_sessions(session_id),
                    FOREIGN KEY (proposing_agent_id) REFERENCES agents(agent_id)
                );

