-- collective_reasoning_sessions
CREATE TABLE collective_reasoning_sessions (
                    session_id TEXT PRIMARY KEY,
                    game_id TEXT NOT NULL,
                    generation INTEGER NOT NULL,
                    
                    -- Participating agents
